data: {"type": "text-start", "id": "a5b79980-cb5d-48c0-8d4c-c89cd69a37c1"}

data: {"type": "text-delta", "id": "a5b79980-cb5d-48c0-8d4c-c89cd69a37c1", "delta": "1. `SELECT client_addr, state, sync_state, query FROM pg_stat_replication;`\n2. `SELECT pg_wal_lsn_diff(pg_current_wal_lsn(), replay_lsn) AS lag_bytes FROM pg_stat_replication;`\n3. `SELECT * FROM pg_stat_activity WHERE state = 'idle in transaction';`\n4. `SELECT count(*) FROM pg_stat_activity WHERE state = 'active';`\n5. `SELECT pg_last_wal_receive_lsn(), pg_last_wal_replay_lsn(), pg_current_wal_lsn();`"}

data: {"type": "text-end", "id": "a5b79980-cb5d-48c0-8d4c-c89cd69a37c1"}

