data: {"type": "start", "messageId": "43d3600f-9302-4476-ae9d-b7cb603c0d6a"}

data: {"type": "text-start", "id": "66415cc0-3d43-4085-9eb3-bab9f1e333db"}

data: {"type": "text-delta", "id": "66415cc0-3d43-4085-9eb3-bab9f1e333db", "delta": "1. `SELECT client_addr, state, sync_state, query FROM pg_stat_replication;`\n2. `SELECT pg_wal_lsn_diff(pg_current_wal_lsn(), replay_lsn) AS lag_bytes FROM pg_stat_replication;`\n3. `SELECT datname, state, sent_lsn, write_lsn, flush_lsn, replay_lsn FROM pg_stat_replication;`\n4. `SELECT * FROM pg_stat_activity WHERE state = 'idle in transaction';`\n5. `SELECT count(*) FROM pg_stat_replication WHERE state != 'streaming';`"}

data: {"type": "text-end", "id": "66415cc0-3d43-4085-9eb3-bab9f1e333db"}

