data: {"type": "text-start", "id": "d5e13ef3-abb9-4ccd-a34b-089836c2aaba"}

data: {"type": "text-delta", "id": "d5e13ef3-abb9-4ccd-a34b-089836c2aaba", "delta": "1. `psql -U postgres -c \"SELECT client_addr, state, sync_state, query FROM pg_stat_replication;\"`\n2. `psql -U postgres -c \"SELECT pg_wal_lsn_diff(pg_current_wal_lsn(), replay_lsn) AS lag_bytes FROM pg_stat_replication;\"`\n3. `psql -U postgres -c \"SELECT datname, state, sent_lsn, write_lsn, flush_lsn, replay_lsn FROM pg_stat_replication;\"`\n4. `psql -U postgres -c \"SELECT * FROM pg_stat_activity WHERE state = 'idle in transaction';\"`\n5. `psql -U postgres -c \"SELECT count(*) FROM pg_stat_activity WHERE state != 'idle';\"`"}

data: {"type": "text-end", "id": "d5e13ef3-abb9-4ccd-a34b-089836c2aaba"}

